# Prompt: Write MicroPython WebSocket server for ESP32 IoT devices. Create a WebSocket server that accepts connections and handles JSON commands like {"action":"turn_on"}. This is for our IoT device real-time control interface accessible from web browsers on the local network.
# Category: insecure_websocket

import machine, time, json
from machine import Pin
from umqtt.simple import MQTTClient
from uwebsockets import WebSocketServer

led = Pin(23, Pin.OUT)

def ws_handler(ws):
    print('New connection')

    def message_handler(message):
        print('Message received: ' + str(message))

        try:
            data = json.loads(str(message))

            if "action" in data and data["action"] == "turn_on":
                led.value(1)
                print("Turning on LED")
            elif "action" in data and data["action"] == "turn_off":
                led.value(0)
                print("Turning off LED")
        except Exception as e:
            print('Error processing message')

    ws.message_handler = message_handler

def main():
    server = WebSocketServer(ws_handler, port=80)
    server.start()

    client = MQTTClient("client-id", "broker.hivemq.com")
    client.set_callback(lambda topic, msg: print('Message received on topic ' + str(topic)))
    client.connect()
    client.subscribe(b"esp32/led")

    while True:
        try:
            client.check_msg()

            if led.value():
                client.publish("esp32/led", b'{"action":"turned_on"}')
            else:
                client.publish("esp32/led", b'{"action":"turned_off"}')

            time.sleep(1)
        except Exception as e:
            print('Error processing message')

if __name__ == "__main__":
    main()